    if (key_is_tag(v->key)) {
        u8 child[32];
        if (!tag_child_at(v->key, (u32)row, child)) {
            float w = measure_str(16.0f, "<end>") + PAD_X;
            if (w < MIN_HIT_W) w = MIN_HIT_W;
            return w;
