    H token;
    /* Restart the current block in-place.  Calling cvm_exec(current_key) would
     * enter the same block through cvm_set_current again and leak call frames
     * on every loop iteration. */
    cvm_restart_current();
    memcpy(token, ptr, 32);
    cvm_exec(token);
