    if (nm && !strcmp(nm, "cond_token_payload") && pn >= 32) {
        u32 uid = (pn >= 36) ? *(u32*)(payload+32) : 0;
        u8 once = (pn >= 38) ? payload[36] : 0;
        u8 contf = (pn >= 38) ? payload[37] : 0;
